                ) {
                    media.take(2).forEach { item ->
                        MediaImage(
                            url = item.url,
                            alt = item.alt,
                            modifier = Modifier
                                .weight(1f)
                                .height(100.dp)
                                .clip(RoundedCornerShape(AppShapes.mediaRadius))
