                if (media.size > 2) {
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        media.drop(2).take(2).forEach { item ->
                            MediaImage(
                                url = item.url,
                                alt = item.alt,
