fun refresh() {
    viewModelScope.launch {
        _uiState.update { it.copy(isRefreshing = true, error = null) }

        repository.getPersonalTimeline(refresh = true)
            .onSuccess { result ->
                lastLoadTime = Instant.now()
                _uiState.update {
                    it.copy(
                        posts = result.posts,
                        hasNextPage = result.hasNextPage,
                        endCursor = result.endCursor,
                        isRefreshing = false
                    )
                }
            }
            .onFailure { error ->
                _uiState.update {
                    it.copy(
                        error = error.message,
                        isRefreshing = false
                    )
                }
            }
    }

