        }
        Text(
            text = text,
            style = style,
            color = color,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
            modifier = modifier
        )
        return
    }

    // Render mixed text + image segments
    Row(
        verticalAlignment = Alignment.CenterVertically,
        modifier = modifier
    ) {
        var charCount = 0
        var truncated = false

        for (segment in segments) {
            if (truncated) break

            when (segment) {
                is DisplayNameSegment.TextSegment -> {
                    val remaining = if (maxChars > 0) maxChars - charCount else Int.MAX_VALUE
                    if (remaining <= 0) {
                        truncated = true
                        break
                    }
                    val text = if (maxChars > 0 && segment.text.length > remaining) {
                        truncated = true
                        segment.text.take(remaining) + "\u2026"
                    } else {
                        segment.text
                    }
                    charCount += segment.text.length
                    Text(
                        text = text,
                        style = style,
                        color = color,
                        maxLines = 1,
                        overflow = TextOverflow.Clip
                    )
                }
                is DisplayNameSegment.ImageSegment -> {
                    AsyncImage(
                        model = segment.src,
                        contentDescription = segment.alt,
                        modifier = Modifier
                            .height(emojiHeight)
                            .padding(horizontal = 1.dp)
                            .clip(RoundedCornerShape(2.dp)),
                        contentScale = ContentScale.FillHeight
                    )
                    // Count emoji as 1 character for truncation purposes
                    charCount += 1
                }
            }
        }
    }
}

