        if (viewerBlocks) {
            Text(
                text = stringResource(R.string.blocked),
                style = typography.caption,
                color = colors.reaction,
                modifier = Modifier
                    .background(
                        colors.reaction.copy(alpha = 0.10f),
                        RoundedCornerShape(AppShapes.tagRadius)
                    )
                    .padding(horizontal = 8.dp, vertical = 4.dp)
            )
        }
    }
}

